import "../quiz_question.dart";

const _subject = "Arabic";

QuizQuestion _q(String text, List<String> options, String correct, String explanation) {
  return QuizQuestion(
    subject: _subject,
    text: text,
    options: options,
    correctIndex: options.indexOf(correct),
    explanation: explanation,
  );
}

/// University of Ibadan (UI) Post-UTME Arabic elective bank — 100
/// questions covering the same five broad areas commonly tested in
/// JAMB/Post-UTME Arabic screening: Comprehension (المطالعة), Translation
/// (الترجمة), Grammar and Structure (النحو والصرف), Composition
/// (الإنشاء), and Arabic Literature (الأدب العربي). Literature questions
/// are limited to well-documented author/era-level facts rather than
/// fine-grained plot or text detail, to avoid fabricated specifics.
/// This is a general-purpose practice set, not an official UI past-question
/// paper; always confirm the exact format and syllabus on UI's own
/// screening portal for the current session.
List<QuizQuestion> buildUiArabicQuestions() {
  return [
    ..._comprehension,
    ..._translation,
    ..._grammarAndStructure,
    ..._composition,
    ..._arabicLiterature,
  ];
}

